import { describe, it, expect } from 'vitest';
import { execFileSync } from 'node:child_process';
import { fileURLToPath } from 'node:url';
import { dirname, resolve } from 'node:path';

const here = dirname(fileURLToPath(import.meta.url));
const cliPath = resolve(here, 'cli.ts');

type RunResult = { stdout: string; stderr: string; status: number };

function runCli(input: unknown): RunResult {
  try {
    const stdout = execFileSync('npx', ['tsx', cliPath], {
      input: JSON.stringify(input),
      encoding: 'utf8',
      stdio: ['pipe', 'pipe', 'pipe'],
    });
    return { stdout, stderr: '', status: 0 };
  } catch (err) {
    const e = err as { stdout?: Buffer | string; stderr?: Buffer | string; status?: number };
    return {
      stdout: e.stdout?.toString() ?? '',
      stderr: e.stderr?.toString() ?? '',
      status: e.status ?? 1,
    };
  }
}

function parseResults(input: unknown): Array<Record<string, number>> {
  const { stdout, status, stderr } = runCli(input);
  if (status !== 0) throw new Error(`CLI failed: ${stderr}`);
  const parsed = JSON.parse(stdout) as { results: Array<Record<string, number>> };
  return parsed.results;
}

describe('claim-office CLI', () => {
  describe('empty quote', () => {
    it('returns only the 5 G processing fee', () => {
      const results = parseResults({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: 'quote', items: [] }],
      });
      expect(results).toEqual([{ premium: 5 }]);
    });
  });
});

