#!/usr/bin/env node
import { readFileSync } from 'node:fs';

type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
};

type Step = QuoteStep | ClaimStep;

type QuoteStep = { op: 'quote'; items: Item[] };
type ClaimStep = { op: 'claim'; policy: number; incident: Incident };

type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};

type Incident = {
  cause: string;
  damages: Damage[];
};

type Damage = { itemType: string; amount: number };

type Result = QuoteResult | ClaimResult;
type QuoteResult = { premium: number };
type ClaimResult = { payout: number; remainingCap: number };

function readStdin(): string {
  return readFileSync(0, 'utf8');
}

function processScenario(scenario: Scenario): { results: Result[] } {
  const results: Result[] = [];
  for (const step of scenario.steps) {
    if (step.op === 'quote') {
      results.push(quote(step));
    }
  }
  return { results };
}

const PROCESSING_FEE = 5;

function quote(_step: QuoteStep): QuoteResult {
  return { premium: PROCESSING_FEE };
}

function main(): void {
  const raw = readStdin();
  const scenario = JSON.parse(raw) as Scenario;
  const out = processScenario(scenario);
  process.stdout.write(JSON.stringify(out));
}

main();

