  return { premium: roundUp(total) };
}

function roundUp(n: number): number {
  return Math.ceil(n);
}

function main(): void {
  const raw = readStdin();
  const scenario = JSON.parse(raw) as Scenario;
  const out = processScenario(scenario);
  process.stdout.write(JSON.stringify(out));
}

main();

