      const items = [
        { type: 'rune' }, { type: 'rune' }, { type: 'rune' },
        { type: 'moonstone' }, { type: 'moonstone' }, { type: 'moonstone' },
      ];
      expect(
        run({ customer: { yearsWithMHPCO: 0 }, steps: [{ op: 'quote', items }] }),
      ).toEqual([{ premium: 137 }]);
    });
  });

