    // 7 runes: 175 base (no block), +17.5, +5 = 197.5 → rounded up = 198
    it.each([
      [2, 60],
      [3, 71],
      [4, 115],
      [7, 198],
    ])('%i runes → premium %i G', (n, expected) => {
